import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import './AuthPages.css';

const STATES = [
  'Andhra Pradesh','Arunachal Pradesh','Assam','Bihar','Chhattisgarh','Goa','Gujarat',
  'Haryana','Himachal Pradesh','Jharkhand','Karnataka','Kerala','Madhya Pradesh',
  'Maharashtra','Manipur','Meghalaya','Mizoram','Nagaland','Odisha','Punjab',
  'Rajasthan','Sikkim','Tamil Nadu','Telangana','Tripura','Uttar Pradesh',
  'Uttarakhand','West Bengal','Delhi','Other',
];

export default function RegisterPage() {
  const { login, addToast } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    firstName: '', lastName: '', email: '', username: '',
    college: '', department: '', position: '', phone: '', state: '', password: '', confirm: '',
  });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.firstName.trim()) e.firstName = 'Required';
    if (!form.lastName.trim()) e.lastName = 'Required';
    if (!form.email.trim() || !/\S+@\S+\.\S+/.test(form.email)) e.email = 'Valid email required';
    if (!form.username.trim()) e.username = 'Required';
    if (!form.college.trim()) e.college = 'Required';
    if (!form.phone.trim() || !/^\d{10}$/.test(form.phone)) e.phone = '10-digit phone required';
    if (!form.state) e.state = 'Required';
    if (!form.password || form.password.length < 8) e.password = 'Minimum 8 characters';
    if (form.password !== form.confirm) e.confirm = 'Passwords do not match';
    return e;
  };

  const handleSubmit = async (ev) => {
    ev.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    await new Promise(r => setTimeout(r, 800));
    login({ username: form.username, firstName: form.firstName, lastName: form.lastName });
    addToast('Account created! Welcome to FOSSEE Workshops.', 'success');
    navigate('/');
    setLoading(false);
  };

  const set = (field) => (e) => {
    setForm(p => ({ ...p, [field]: e.target.value }));
    if (errors[field]) setErrors(p => ({ ...p, [field]: null }));
  };

  const Field = ({ id, label, type = 'text', placeholder, required, autoComplete }) => (
    <div className="form-group">
      <label className="form-label" htmlFor={id}>
        {label}{required && <span className="required-star" aria-hidden="true"> *</span>}
      </label>
      <input
        id={id}
        className={`form-control${errors[id] ? ' form-control-error' : ''}`}
        type={type}
        value={form[id]}
        onChange={set(id)}
        placeholder={placeholder}
        autoComplete={autoComplete}
        aria-invalid={!!errors[id]}
        aria-describedby={errors[id] ? `${id}-error` : undefined}
      />
      {errors[id] && <span className="form-error" id={`${id}-error`} role="alert">{errors[id]}</span>}
    </div>
  );

  return (
    <div className="auth-page auth-page-wide">
      <div className="auth-card auth-card-wide">
        <div className="auth-header">
          <div className="auth-icon" aria-hidden="true">🎓</div>
          <h1>Create your account</h1>
          <p>Register as a workshop coordinator</p>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div className="form-section-title">Personal Details</div>
          <div className="form-row-2">
            <Field id="firstName" label="First Name" placeholder="Rahul" required autoComplete="given-name" />
            <Field id="lastName" label="Last Name" placeholder="Sharma" required autoComplete="family-name" />
          </div>
          <Field id="email" label="Email Address" type="email" placeholder="rahul@college.edu" required autoComplete="email" />
          <Field id="username" label="Username" placeholder="rahul_sharma" required autoComplete="username" />
          <Field id="phone" label="Phone Number" type="tel" placeholder="9876543210" required autoComplete="tel" />

          <div className="form-section-title">College Details</div>
          <Field id="college" label="College / Institute Name" placeholder="IIT Bombay" required />
          <Field id="department" label="Department" placeholder="Computer Science" />
          <Field id="position" label="Position / Designation" placeholder="Assistant Professor" />

          <div className="form-group">
            <label className="form-label" htmlFor="state">
              State <span className="required-star" aria-hidden="true">*</span>
            </label>
            <select
              id="state"
              className={`form-control${errors.state ? ' form-control-error' : ''}`}
              value={form.state}
              onChange={set('state')}
              aria-invalid={!!errors.state}
            >
              <option value="">Select your state</option>
              {STATES.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
            {errors.state && <span className="form-error" id="state-error" role="alert">{errors.state}</span>}
          </div>

          <div className="form-section-title">Set Password</div>
          <Field id="password" label="Password" type="password" placeholder="Minimum 8 characters" required autoComplete="new-password" />
          <Field id="confirm" label="Confirm Password" type="password" placeholder="Repeat your password" required autoComplete="new-password" />

          <button
            type="submit"
            className="btn btn-primary"
            style={{ width: '100%', marginTop: '8px' }}
            disabled={loading}
          >
            {loading ? (
              <><span className="spinner" aria-hidden="true"></span>Creating account…</>
            ) : 'Create Account'}
          </button>
        </form>

        <div className="auth-footer">
          <p>Already have an account? <Link to="/login">Sign in</Link></p>
        </div>
      </div>
    </div>
  );
}
